    x = blockIdx_y * TILE_DIM + threadIdx.x;
    y = blockIdx_x * TILE_DIM + threadIdx.y;

    // Store with coalescing
    #pragma unroll
    for (int j = 0; j < TILE_DIM; j += BLOCK_ROWS) {
        int store_y = y + j;
        if (store_y < N && x < M) {
            output[store_y * M + x] = tile[threadIdx.x][threadIdx.y + j];
        }
    }
}

